import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
  useLocation,
} from "react-router-dom";
import { useState } from "react";
import classes from "./components/app.module.css";
import Home from "../components/pages/Home";
import Login from "../components/pages/Login";
import CalorieCalc from "../components/pages/CalorieCalc";
import Profile from "./pages/Profile";
import NavBar from "../components/navBar/NavBar";
import NotFound from "../components/pages/NotFound";

export default function App() {
  const RequireAuth = ({ children, isLoggedIn }) => {
    const location = useLocation();
  };
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);

  const pages = [
    { name: "Login", path: "/" },
    { name: "Home", path: "/home" },
    { name: "CalorieCalculator", path: "/CalorieCalc" },
    { name: "Profile", path: "/profile" },
  ];

  const handleLogin = (user) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
  };

  return (
    <>
      <Router>
        <NavBar
          pages={pages}
          isLoggedIn={isLoggedIn}
          onLogout={handleLogout}
          currentUser={currentUser}
        />
        <section className={classes.app}>
          <Routes>
            <Route path="/" element={<Login onLoginSuccess={handleLogin} />} />
            <Route
              path="/home"
              element={
                <RequireAuth isLoggedIn={isLoggedIn}>
                  <Home />
                </RequireAuth>
              }
            />
            <Route
              path="/CalorieCalc"
              element={
                <RequireAuth isLoggedIn={isLoggedIn}>
                  <CalorieCalc />
                </RequireAuth>
              }
            />
            <Route
              path="/profile"
              element={
                <RequireAuth isLoggedIn={isLoggedIn}>
                  <Profile currentUser={currentUser} />
                </RequireAuth>
              }
            />
            <Route path="*" element={<NotFound />} />
          </Routes>
        </section>
      </Router>
      <Footer />
    </>
  );
}
